export interface ChannelProfile {
  name: string;
  niche: string;
  description: string;
  brandingStyle: string;
  logoUrl?: string;
  bannerUrl?: string;
}

export interface VideoContent {
  id: string;
  title: string;
  description: string;
  script: string;
  tags: string[];
  thumbnailUrl?: string;
  videoUrl?: string;
  status: 'draft' | 'scheduled' | 'published';
  createdAt: string;
}

export type ViewType = 'dashboard' | 'branding' | 'studio' | 'media' | 'analytics';

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ChannelProfile, VideoContent } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateChannelBranding = async (niche: string): Promise<ChannelProfile> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a YouTube channel profile for the niche: "${niche}".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          brandingStyle: { type: Type.STRING, description: "Visual style description (e.g. minimalist, futuristic, retro)" },
        },
        required: ["name", "description", "brandingStyle"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return { ...data, niche };
};

export const generateContentIdea = async (channel: ChannelProfile, topic: string): Promise<Partial<VideoContent>> => {
  const ai = getAIClient();
  const prompt = `Act as a YouTube strategist for a channel called "${channel.name}" in the niche "${channel.niche}". 
  Generate a video concept based on topic: "${topic}". Include title, description, keywords, and a short script.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          script: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["title", "description", "script", "tags"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateThumbnail = async (title: string, style: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High-quality YouTube thumbnail for a video titled "${title}". Style: ${style}. Vibrant colors, eye-catching text placement, 4k, cinematic.` }]
    },
    config: {
      imageConfig: { aspectRatio: "16:9" }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image");
};

export const generateVideoClip = async (prompt: string): Promise<string> => {
  const ai = getAIClient();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

