export default Sidebar;

import React, { useState } from 'react';
import { ChannelProfile } from '../types';
import { generateChannelBranding } from '../services/geminiService';
import { Sparkles, Save, RefreshCw } from 'lucide-react';

interface BrandingViewProps {
  profile: ChannelProfile | null;
  onUpdate: (profile: ChannelProfile) => void;
}

const BrandingView: React.FC<BrandingViewProps> = ({ profile, onUpdate }) => {
  const [niche, setNiche] = useState(profile?.niche || '');
  const [loading, setLoading] = useState(false);
  const [localProfile, setLocalProfile] = useState<ChannelProfile | null>(profile);

  const handleGenerate = async () => {
    if (!niche) return;
    setLoading(true);
    try {
      const result = await generateChannelBranding(niche);
      setLocalProfile(result);
    } catch (error) {
      console.error(error);
      alert("Failed to generate branding. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    if (localProfile) {
      onUpdate(localProfile);
      alert("Channel Profile Saved!");
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="bg-zinc-900/50 p-8 rounded-3xl border border-zinc-800">
        <h2 className="text-2xl font-bold mb-2">Channel Architect</h2>
        <p className="text-zinc-400 mb-6">Define your niche and let Gemini build your brand identity.</p>

        <div className="flex gap-4 mb-8">
          <input
            type="text"
            value={niche}
            onChange={(e) => setNiche(e.target.value)}
            placeholder="e.g., Space Exploration, Cooking for Students, AI News"
            className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all"
          />
          <button
            onClick={handleGenerate}
            disabled={loading}
            className="bg-white text-black font-semibold px-6 py-3 rounded-xl hover:bg-zinc-200 transition-colors flex items-center gap-2 disabled:opacity-50"
          >
            {loading ? <RefreshCw className="animate-spin w-5 h-5" /> : <Sparkles className="w-5 h-5" />}
            {localProfile ? 'Regenerate' : 'Architect Channel'}
          </button>
        </div>

        {localProfile && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in slide-in-from-bottom-4">
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase">Channel Name</label>
                <div className="text-xl font-bold text-white mt-1">{localProfile.name}</div>
              </div>
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase">Description</label>
                <p className="text-zinc-300 mt-1 leading-relaxed">{localProfile.description}</p>
              </div>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase">Branding Style</label>
                <div className="inline-block px-3 py-1 bg-zinc-800 rounded-full text-zinc-300 mt-2">
                  {localProfile.brandingStyle}
                </div>
              </div>
              <div className="pt-4 flex gap-4">
                <button
                  onClick={handleSave}
                  className="flex-1 bg-red-600 text-white font-bold py-3 rounded-xl hover:bg-red-700 transition-colors flex items-center justify-center gap-2"
                >
                  <Save className="w-5 h-5" /> Save Identity
                </button>
              </div>
            </div>
          </div>
        )}
      </div>

      {localProfile && (
        <div className="grid grid-cols-3 gap-6">
          <div className="aspect-square bg-zinc-900 rounded-3xl border border-zinc-800 flex flex-col items-center justify-center p-6 text-center">
             <div className="w-20 h-20 rounded-full bg-gradient-to-tr from-red-500 to-orange-500 mb-4 shadow-lg shadow-red-500/20" />
             <p className="font-bold">Profile Logo</p>
             <p className="text-xs text-zinc-500 mt-2">AI-Generated Vector</p>
          </div>
          <div className="col-span-2 aspect-[3/1] bg-zinc-900 rounded-3xl border border-zinc-800 flex flex-col items-center justify-center p-6 text-center">
             <div className="w-full h-12 bg-gradient-to-r from-zinc-800 via-zinc-700 to-zinc-800 rounded-lg mb-4" />
             <p className="font-bold">Channel Banner</p>
             <p className="text-xs text-zinc-500 mt-2">Panoramic Hero Image</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default BrandingView;

import React, { useState } from 'react';
import { ChannelProfile, VideoContent } from '../types';
import { generateContentIdea, generateThumbnail, generateVideoClip } from '../services/geminiService';
import { FileText, Image as ImageIcon, Video, Send, Loader2, Wand2 } from 'lucide-react';

interface StudioViewProps {
  profile: ChannelProfile | null;
  onPost: (video: VideoContent) => void;
}

const StudioView: React.FC<StudioViewProps> = ({ profile, onPost }) => {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState<string | null>(null);
  const [content, setContent] = useState<Partial<VideoContent> | null>(null);

  if (!profile) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-zinc-500 gap-4">
        <p className="text-xl">Please architect your channel first.</p>
      </div>
    );
  }

  const handleCreateIdea = async () => {
    if (!topic) return;
    setLoading('content');
    try {
      const result = await generateContentIdea(profile, topic);
      setContent(result);
    } catch (error) {
      alert("Idea generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateThumbnail = async () => {
    if (!content?.title) return;
    setLoading('thumbnail');
    try {
      const url = await generateThumbnail(content.title, profile.brandingStyle);
      setContent(prev => ({ ...prev, thumbnailUrl: url }));
    } catch (error) {
      alert("Thumbnail generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateClip = async () => {
    if (!content?.title) return;
    setLoading('clip');
    try {
      const url = await generateVideoClip(`High quality YouTube video snippet for: ${content.title}`);
      setContent(prev => ({ ...prev, videoUrl: url }));
    } catch (error) {
      alert("Video clip generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handlePost = () => {
    if (content?.title) {
      onPost({
        ...content as VideoContent,
        id: Math.random().toString(36).substr(2, 9),
        status: 'published',
        createdAt: new Date().toISOString()
      });
      alert("Video Published Successfully!");
      setContent(null);
      setTopic('');
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20">
      <div className="bg-zinc-900/50 p-8 rounded-3xl border border-zinc-800">
        <h2 className="text-2xl font-bold mb-2">Content Studio</h2>
        <p className="text-zinc-400 mb-6">Create high-performance content for {profile.name}.</p>

        <div className="flex gap-4 mb-8">
          <input
            type="text"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="Enter a video topic or idea..."
            className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all"
          />
          <button
            onClick={handleCreateIdea}
            disabled={!!loading}
            className="bg-red-600 text-white font-bold px-8 py-3 rounded-xl hover:bg-red-700 transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {loading === 'content' ? <Loader2 className="animate-spin w-5 h-5" /> : <Wand2 className="w-5 h-5" />}
            Generate Script
          </button>
        </div>

        {content && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-bottom-6">
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center gap-2 text-red-500 mb-4">
                  <FileText className="w-4 h-4" />
                  <span className="text-xs font-bold uppercase tracking-wider">Draft Script</span>
                </div>
                <h3 className="text-2xl font-bold mb-4">{content.title}</h3>
                <div className="prose prose-invert max-w-none">
                  <p className="text-zinc-300 whitespace-pre-line leading-relaxed h-[300px] overflow-y-auto pr-4">
                    {content.script}
                  </p>
                </div>
                <div className="mt-6 flex flex-wrap gap-2">
                  {content.tags?.map(tag => (
                    <span key={tag} className="px-3 py-1 bg-zinc-900 border border-zinc-800 rounded-lg text-xs text-zinc-400">
                      #{tag}
                    </span>
                  ))}
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2 text-indigo-500">
                    <ImageIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Thumbnail</span>
                  </div>
                  <button 
                    onClick={handleGenerateThumbnail}
                    disabled={!!loading}
                    className="text-xs font-bold hover:text-white text-zinc-500 underline disabled:opacity-50"
                  >
                    {loading === 'thumbnail' ? 'Generating...' : 'Generate New'}
                  </button>
                </div>
                <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden flex items-center justify-center border border-dashed border-zinc-700 relative">
                  {content.thumbnailUrl ? (
                    <img src={content.thumbnailUrl} className="w-full h-full object-cover" alt="Thumbnail" />
                  ) : (
                    <p className="text-zinc-600 text-sm">No thumbnail generated</p>
                  )}
                  {loading === 'thumbnail' && <div className="absolute inset-0 bg-black/60 flex items-center justify-center"><Loader2 className="animate-spin text-white" /></div>}
                </div>
              </div>

              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2 text-purple-500">
                    <Video className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Short Clip</span>
                  </div>
                  <button 
                    onClick={handleGenerateClip}
                    disabled={!!loading}
                    className="text-xs font-bold hover:text-white text-zinc-500 underline disabled:opacity-50"
                  >
                    {loading === 'clip' ? 'Generating (Veo)...' : 'Create Clip'}
                  </button>
                </div>
                <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden flex items-center justify-center border border-dashed border-zinc-700 relative">
                  {content.videoUrl ? (
                    <video src={content.videoUrl} controls className="w-full h-full object-cover" />
                  ) : (
                    <p className="text-zinc-600 text-sm">No video preview</p>
                  )}
                  {loading === 'clip' && <div className="absolute inset-0 bg-black/60 flex items-center justify-center text-center p-4"><div className="flex flex-col items-center"><Loader2 className="animate-spin text-white mb-2" /><span className="text-[10px] text-zinc-300">Veo is processing... this may take 20s</span></div></div>}
                </div>
              </div>

              <button
                onClick={handlePost}
                disabled={!content.title || !!loading}
                className="w-full bg-white text-black font-black py-4 rounded-2xl hover:bg-zinc-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-white/5"
              >
                <Send className="w-5 h-5" /> PUBLISH TO YOUTUBE
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudioView;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import BrandingView from './components/BrandingView';
import StudioView from './components/StudioView';
import DashboardView from './components/DashboardView';
import { ViewType, ChannelProfile, VideoContent } from './types';
import { Key, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [channelProfile, setChannelProfile] = useState<ChannelProfile | null>(null);
  const [publishedVideos, setPublishedVideos] = useState<VideoContent[]>([]);
  const [isKeySelected, setIsKeySelected] = useState(false);

  // Check for API key on mount
  useEffect(() => {
    const checkKey = async () => {
      // In this environment, we assume process.env.API_KEY is handled, 
      // but for Veo we must explicitly trigger the selection UI.
      if (typeof window.aistudio?.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(hasKey);
      } else {
        // Fallback for non-Veo restricted environments
        setIsKeySelected(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    if (typeof window.aistudio?.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setIsKeySelected(true); // Assume success per instructions
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <DashboardView profile={channelProfile} publishedVideos={publishedVideos} />;
      case 'branding':
        return <BrandingView profile={channelProfile} onUpdate={setChannelProfile} />;
      case 'studio':
        return <StudioView profile={channelProfile} onPost={(v) => setPublishedVideos(prev => [v, ...prev])} />;
      case 'analytics':
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-zinc-500">
            <BarChart3 className="w-16 h-16 mb-4 opacity-20" />
            <h3 className="text-xl font-bold text-white">Advanced Insights</h3>
            <p>Gathering enough data points to generate meaningful analytics...</p>
          </div>
        );
      case 'media':
        return (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            {publishedVideos.map(v => (
              <div key={v.id} className="space-y-2">
                <div className="aspect-square bg-zinc-900 rounded-3xl overflow-hidden border border-zinc-800">
                   {v.thumbnailUrl && <img src={v.thumbnailUrl} className="w-full h-full object-cover" />}
                </div>
                <p className="text-xs font-bold truncate px-2">{v.title}</p>
              </div>
            ))}
            {publishedVideos.length === 0 && (
               <p className="col-span-full text-center py-20 text-zinc-500">Your AI media library is empty.</p>
            )}
          </div>
        );
      default:
        return <DashboardView profile={channelProfile} publishedVideos={publishedVideos} />;
    }
  };

  if (!isKeySelected) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#0f0f0f] p-6">
        <div className="max-w-md w-full bg-zinc-900 border border-zinc-800 p-8 rounded-[2rem] shadow-2xl text-center">
          <div className="w-16 h-16 bg-red-600/10 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <Key className="w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold mb-4">API Key Required</h1>
          <p className="text-zinc-400 mb-8 leading-relaxed">
            To use high-quality video generation (Veo) and image generation, you must select your Google AI Studio API key.
          </p>
          <div className="space-y-4">
            <button
              onClick={handleOpenKeySelector}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-2xl transition-all shadow-lg shadow-red-600/20"
            >
              Select API Key
            </button>
            <a 
              href="https://ai.google.dev/gemini-api/docs/billing" 
              target="_blank" 
              className="block text-sm text-zinc-500 hover:text-white transition-colors"
            >
              View Billing Documentation
            </a>
          </div>
          <div className="mt-8 flex items-start gap-3 p-4 bg-zinc-950 rounded-xl border border-zinc-800 text-left">
            <AlertCircle className="w-5 h-5 text-indigo-500 flex-shrink-0 mt-0.5" />
            <p className="text-[10px] text-zinc-500 uppercase font-black tracking-widest">
              Note: TubeAI Studio uses advanced 2.5 and 3.0 models which require a verified project.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#0f0f0f] text-white overflow-hidden">
      <Sidebar currentView={currentView} setView={setView} />

      <main className="flex-1 overflow-y-auto relative">
        <header className="sticky top-0 z-30 bg-[#0f0f0f]/80 backdrop-blur-md border-b border-zinc-800 px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <h2 className="text-lg font-bold capitalize">{currentView}</h2>
            {channelProfile && (
              <div className="flex items-center gap-2 px-3 py-1 bg-zinc-900 rounded-full border border-zinc-800">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                <span className="text-xs font-bold text-zinc-400">{channelProfile.name}</span>
              </div>
            )}
          </div>
          <div className="flex items-center gap-4">
            <div className="flex -space-x-2">
               {[1,2,3].map(i => (
                 <img key={i} src={`https://picsum.photos/32/32?random=${i}`} className="w-8 h-8 rounded-full border-2 border-[#0f0f0f]" />
               ))}
            </div>
