import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ChannelProfile, VideoContent } from "../types";

const getAIClient = () => {
  // Create a new instance right before use as per instructions for Veo/Paid keys
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateChannelBranding = async (niche: string): Promise<ChannelProfile> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a YouTube channel profile for the niche: "${niche}".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          brandingStyle: { type: Type.STRING, description: "Visual style description (e.g. minimalist, futuristic, retro)" },
        },
        required: ["name", "description", "brandingStyle"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return { ...data, niche };
};

export const generateContentIdea = async (channel: ChannelProfile, topic: string): Promise<Partial<VideoContent>> => {
  const ai = getAIClient();
  const prompt = `Act as a YouTube strategist for a channel called "${channel.name}" in the niche "${channel.niche}". 
  Generate a video concept based on topic: "${topic}". Include title, description, keywords, and a short script.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          script: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["title", "description", "script", "tags"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateThumbnail = async (title: string, style: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High-quality YouTube thumbnail for a video titled "${title}". Style: ${style}. Vibrant colors, eye-catching text placement, 4k, cinematic.` }]
    },
    config: {
      imageConfig: { aspectRatio: "16:9" }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image");
};

export const generateStoryboard = async (title: string, script: string): Promise<string> => {
  const ai = getAIClient();
  const prompt = `Based on the video title "${title}" and script, create a detailed visual storyboard. 
  Describe exactly what should be shown on screen for each major scene. Break it down into "Scene 1: Visuals...", "Scene 2: Visuals...". 
  Focus on lighting, camera angles, and action.

  Script: ${script}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text || "No storyboard generated.";
};

export const generateVideoClip = async (prompt: string): Promise<string> => {
  const ai = getAIClient();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed to return a link.");

  // Use the current API key from environment for the download link
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!response.ok) throw new Error("Failed to download video file.");

  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

import React, { useState, useEffect } from 'react';
import { ChannelProfile, VideoContent } from '../types';
import { generateContentIdea, generateThumbnail, generateStoryboard, generateVideoClip } from '../services/geminiService';
import { FileText, Image as ImageIcon, Layout, Send, Loader2, Wand2, Video, Sparkles } from 'lucide-react';

interface StudioViewProps {
  profile: ChannelProfile | null;
  onPost: (video: VideoContent) => void;
}

const StudioView: React.FC<StudioViewProps> = ({ profile, onPost }) => {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState<string | null>(null);
  const [content, setContent] = useState<Partial<VideoContent> | null>(null);
  const [videoProgressMsg, setVideoProgressMsg] = useState('');

  const loadingMessages = [
    "Veo is imagining your scenes...",
    "Rendering high-quality frames...",
    "Stitching cinematic transitions...",
    "Almost ready to premiere...",
    "Polishing visual effects..."
  ];

  useEffect(() => {
    let interval: number;
    if (loading === 'video') {
      let idx = 0;
      setVideoProgressMsg(loadingMessages[0]);
      interval = window.setInterval(() => {
        idx = (idx + 1) % loadingMessages.length;
        setVideoProgressMsg(loadingMessages[idx]);
      }, 5000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  if (!profile) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-zinc-500 gap-4">
        <p className="text-xl">Please architect your channel first.</p>
      </div>
    );
  }

  const handleCreateIdea = async () => {
    if (!topic) return;
    setLoading('content');
    try {
      const result = await generateContentIdea(profile, topic);
      setContent(result);
    } catch (error) {
      alert("Idea generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateThumbnail = async () => {
    if (!content?.title) return;
    setLoading('thumbnail');
    try {
      const url = await generateThumbnail(content.title, profile.brandingStyle);
      setContent(prev => ({ ...prev, thumbnailUrl: url }));
    } catch (error) {
      alert("Thumbnail generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateStoryboard = async () => {
    if (!content?.title || !content.script) return;
    setLoading('storyboard');
    try {
      const result = await generateStoryboard(content.title, content.script);
      setContent(prev => ({ ...prev, storyboard: result }));
    } catch (error) {
      alert("Storyboard generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateVideo = async () => {
    if (!content?.title || !content.storyboard) {
      alert("Please generate a storyboard first to guide the video generation.");
      return;
    }
    setLoading('video');
    try {
      const videoPrompt = `A high-quality cinematic video clip for a YouTube video titled "${content.title}". Style: ${profile.brandingStyle}. Scene details: ${content.storyboard.substring(0, 500)}`;
      const url = await generateVideoClip(videoPrompt);
      setContent(prev => ({ ...prev, videoUrl: url }));
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
        alert("Veo session error. You might need to re-select your API key.");
      } else {
        alert("Video generation failed. Ensure your API key has Veo access.");
      }
    } finally {
      setLoading(null);
    }
  };

  const handlePost = () => {
    if (content?.title) {
      onPost({
        ...content as VideoContent,
        id: Math.random().toString(36).substr(2, 9),
        status: 'published',
        createdAt: new Date().toISOString()
      });
      alert("Content Archived Successfully!");
      setContent(null);
      setTopic('');
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20">
      <div className="bg-zinc-900/50 p-8 rounded-3xl border border-zinc-800 backdrop-blur-sm">
        <h2 className="text-2xl font-bold mb-2">Content Studio</h2>
        <p className="text-zinc-400 mb-6">Create pro-level content for {profile.name} using Gemini & Veo.</p>

        <div className="flex gap-4 mb-8">
          <input
            type="text"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="Enter a video topic or idea..."
            className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all"
          />
          <button
            onClick={handleCreateIdea}
            disabled={!!loading}
            className="bg-red-600 text-white font-bold px-8 py-3 rounded-xl hover:bg-red-700 transition-all flex items-center gap-2 disabled:opacity-50"
          >
            {loading === 'content' ? <Loader2 className="animate-spin w-5 h-5" /> : <Wand2 className="w-5 h-5" />}
            Generate Script
          </button>
        </div>

        {content && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-bottom-6">
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center gap-2 text-red-500 mb-4">
                  <FileText className="w-4 h-4" />
                  <span className="text-xs font-bold uppercase tracking-wider">Draft Script</span>
                </div>
                <h3 className="text-2xl font-bold mb-4">{content.title}</h3>
                <div className="prose prose-invert max-w-none">
                  <p className="text-zinc-300 whitespace-pre-line leading-relaxed h-[400px] overflow-y-auto pr-4 text-sm scrollbar-hide">
