                </div>
                <div className="h-64 bg-zinc-900 rounded-xl overflow-y-auto p-4 border border-zinc-800 relative text-xs text-zinc-400 leading-relaxed">
                  {content.storyboard ? (
                    <div className="whitespace-pre-line">{content.storyboard}</div>
                  ) : (
                    <div className="flex items-center justify-center h-full text-zinc-600 italic text-center">
                      Plan your visuals to enable high-quality video generation.
                    </div>
                  )}
                  {loading === 'storyboard' && <div className="absolute inset-0 bg-black/60 flex items-center justify-center"><Loader2 className="animate-spin text-white" /></div>}
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2 text-indigo-500">
                    <ImageIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Thumbnail</span>
                  </div>
                  <button 
                    onClick={handleGenerateThumbnail}
                    disabled={!!loading}
                    className="text-xs font-bold hover:text-white text-zinc-500 underline disabled:opacity-50"
                  >
                    {loading === 'thumbnail' ? 'Generating...' : 'Generate New'}
                  </button>
                </div>
                <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden flex items-center justify-center border border-dashed border-zinc-700 relative">
                  {content.thumbnailUrl ? (
