export const generateChannelBranding = async (niche: string): Promise<ChannelProfile> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a YouTube channel profile for the niche: "${niche}".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          brandingStyle: { type: Type.STRING, description: "Visual style description (e.g. minimalist, futuristic, retro)" },
        },
        required: ["name", "description", "brandingStyle"]
      }
    }
  });

  const data = JSON.parse(response.text || '{}');
  return { ...data, niche };
};

export const generateContentIdea = async (channel: ChannelProfile, topic: string): Promise<Partial<VideoContent>> => {
  const ai = getAIClient();
  const prompt = `Act as a YouTube strategist for a channel called "${channel.name}" in the niche "${channel.niche}". 
  Generate a video concept based on topic: "${topic}". Include title, description, keywords, and a short script.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          script: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["title", "description", "script", "tags"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateThumbnail = async (title: string, style: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `High-quality YouTube thumbnail for a video titled "${title}". Style: ${style}. Vibrant colors, eye-catching text placement, 4k, cinematic.` }]
    },
    config: {
      imageConfig: { aspectRatio: "16:9" }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate image");
};

export const generateStoryboard = async (title: string, script: string): Promise<string> => {
  const ai = getAIClient();
  const prompt = `Based on the video title "${title}" and script, create a detailed visual storyboard. 
  Describe exactly what should be shown on screen for each major scene. Break it down into "Scene 1: Visuals...", "Scene 2: Visuals...". 
  Focus on lighting, camera angles, and action.

  Script: ${script}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt
  });

  return response.text || "No storyboard generated.";
};

// Veo Free Alternative: Generate a high-quality cinematic keyframe for motion simulation
export const generateMotionKeyframe = async (prompt: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `${prompt}. Cinematic 4k shot, hyper-realistic, motion blur, masterpiece, highly detailed.` }]
    },
    config: {
      imageConfig: { aspectRatio: "16:9" }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("Failed to generate motion keyframe");
};

import React, { useState, useEffect } from 'react';
import { ChannelProfile, VideoContent } from '../types';
import { generateContentIdea, generateThumbnail, generateStoryboard, generateMotionKeyframe } from '../services/geminiService';
import { FileText, Image as ImageIcon, Layout, Send, Loader2, Wand2, Play, Sparkles } from 'lucide-react';

interface StudioViewProps {
  profile: ChannelProfile | null;
  onPost: (video: VideoContent) => void;
}

const StudioView: React.FC<StudioViewProps> = ({ profile, onPost }) => {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState<string | null>(null);
  const [content, setContent] = useState<Partial<VideoContent> | null>(null);
  const [motionStatus, setMotionStatus] = useState('');

  const loadingMessages = [
    "Synthesizing motion vectors...",
    "Rendering cinematic lighting...",
    "Applying high-fidelity textures...",
    "Calculating camera path...",
    "Finalizing visual sequence..."
  ];

  useEffect(() => {
    let interval: number;
    if (loading === 'video') {
      let idx = 0;
      setMotionStatus(loadingMessages[0]);
      interval = window.setInterval(() => {
        idx = (idx + 1) % loadingMessages.length;
        setMotionStatus(loadingMessages[idx]);
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  if (!profile) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-zinc-500 gap-4">
        <p className="text-xl">Please architect your channel first.</p>
      </div>
    );
  }

  const handleCreateIdea = async () => {
    if (!topic) return;
    setLoading('content');
    try {
      const result = await generateContentIdea(profile, topic);
      setContent(result);
    } catch (error) {
      alert("Idea generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateThumbnail = async () => {
    if (!content?.title) return;
    setLoading('thumbnail');
    try {
      const url = await generateThumbnail(content.title, profile.brandingStyle);
      setContent(prev => ({ ...prev, thumbnailUrl: url }));
    } catch (error) {
      alert("Thumbnail generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateStoryboard = async () => {
    if (!content?.title || !content.script) return;
    setLoading('storyboard');
    try {
      const result = await generateStoryboard(content.title, content.script);
      setContent(prev => ({ ...prev, storyboard: result }));
    } catch (error) {
      alert("Storyboard generation failed.");
    } finally {
      setLoading(null);
    }
  };

  const handleGenerateMotion = async () => {
    if (!content?.title || !content.storyboard) {
      alert("Please generate a storyboard first to guide the motion engine.");
      return;
    }
    setLoading('video');
    try {
      const motionPrompt = `A cinematic visual representation for "${content.title}". ${content.storyboard.substring(0, 300)}. Branding style: ${profile.brandingStyle}`;
      const url = await generateMotionKeyframe(motionPrompt);
      setContent(prev => ({ ...prev, videoUrl: url }));
    } catch (error: any) {
      console.error(error);
      alert("Motion synthesis failed. Check your API limits.");
    } finally {
      setLoading(null);
    }
  };

  const handlePost = () => {
    if (content?.title) {
      onPost({
        ...content as VideoContent,
        id: Math.random().toString(36).substr(2, 9),
        status: 'published',
        createdAt: new Date().toISOString()
      });
      alert("Project Archived Successfully!");
      setContent(null);
      setTopic('');
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20">
      <style>{`
        @keyframes kenburns {
          0% { transform: scale(1) translate(0, 0); }
          50% { transform: scale(1.1) translate(-1%, -1%); }
          100% { transform: scale(1) translate(0, 0); }
        }
        .motion-preview-anim {
          animation: kenburns 15s ease-in-out infinite;
        }
      `}</style>

      <div className="bg-zinc-900/50 p-8 rounded-3xl border border-zinc-800 backdrop-blur-sm">
        <h2 className="text-2xl font-bold mb-2">Content Studio</h2>
        <p className="text-zinc-400 mb-6">Free-tier Cinematic Suite for {profile.name}.</p>

        <div className="flex gap-4 mb-8">
          <input
            type="text"
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="What's your next hit video about?"
            className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all placeholder:text-zinc-700"
          />
          <button
            onClick={handleCreateIdea}
            disabled={!!loading}
            className="bg-red-600 text-white font-bold px-8 py-3 rounded-xl hover:bg-red-700 transition-all flex items-center gap-2 disabled:opacity-50 active:scale-95"
          >
            {loading === 'content' ? <Loader2 className="animate-spin w-5 h-5" /> : <Wand2 className="w-5 h-5" />}
            Craft Idea
          </button>
        </div>

        {content && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in slide-in-from-bottom-6">
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center gap-2 text-red-500 mb-4">
                  <FileText className="w-4 h-4" />
                  <span className="text-xs font-bold uppercase tracking-wider">AI Script</span>
                </div>
                <h3 className="text-2xl font-bold mb-4">{content.title}</h3>
                <div className="prose prose-invert max-w-none">
                  <p className="text-zinc-300 whitespace-pre-line leading-relaxed h-[400px] overflow-y-auto pr-4 text-sm scrollbar-hide">
                    {content.script}
                  </p>
                </div>
              </div>

              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-2 text-purple-500">
                    <Layout className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Visual Planning</span>
                  </div>
                  <button 
                    onClick={handleGenerateStoryboard}
                    disabled={!!loading || !content.script}
                    className="text-xs font-bold hover:text-white text-zinc-500 underline disabled:opacity-50"
                  >
                    {loading === 'storyboard' ? 'Planning...' : 'Generate Storyboard'}
                  </button>
                </div>
                <div className="h-48 bg-zinc-900 rounded-xl overflow-y-auto p-4 border border-zinc-800 relative text-xs text-zinc-500 leading-relaxed italic">
                  {content.storyboard || "Generate a storyboard to begin motion synthesis."}
                  {loading === 'storyboard' && <div className="absolute inset-0 bg-black/60 flex items-center justify-center"><Loader2 className="animate-spin text-white" /></div>}
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4 text-indigo-500">
                  <div className="flex items-center gap-2">
                    <ImageIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Thumbnail</span>
                  </div>
                  <button onClick={handleGenerateThumbnail} disabled={!!loading} className="text-xs font-bold underline">
                    {loading === 'thumbnail' ? '...' : 'Refresh'}
                  </button>
                </div>
                <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 relative">
                  {content.thumbnailUrl && <img src={content.thumbnailUrl} className="w-full h-full object-cover" />}
                  {loading === 'thumbnail' && <div className="absolute inset-0 bg-black/60 flex items-center justify-center"><Loader2 className="animate-spin text-white" /></div>}
                </div>
              </div>

              <div className="bg-zinc-950 p-6 rounded-2xl border border-zinc-800">
                <div className="flex items-center justify-between mb-4 text-orange-500">
                  <div className="flex items-center gap-2">
                    <Play className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Motion Preview</span>
                  </div>
                  <button onClick={handleGenerateMotion} disabled={!!loading || !content.storyboard} className="text-xs font-bold underline">
                    {loading === 'video' ? 'Synthesizing...' : 'Animate'}
                  </button>
                </div>
                <div className="aspect-video bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 relative flex items-center justify-center group">
                  {content.videoUrl ? (
                    <div className="w-full h-full relative overflow-hidden">
                      <img src={content.videoUrl} className="w-full h-full object-cover motion-preview-anim" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none" />
                      <div className="absolute bottom-3 left-3 flex items-center gap-2">
                         <div className="w-1.5 h-1.5 rounded-full bg-red-600 animate-pulse" />
                         <span className="text-[10px] font-bold text-white uppercase tracking-widest">Cinema Engine</span>
                      </div>
                    </div>
                  ) : (
                    <p className="text-zinc-700 text-[10px] uppercase font-bold text-center px-4">Motion Synthesis Idle</p>
                  )}
                  {loading === 'video' && (
                    <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center p-6 text-center">
                      <Loader2 className="animate-spin text-orange-500 w-8 h-8 mb-4" />
                      <p className="text-sm font-medium text-white">{motionStatus}</p>
                      <p className="text-[9px] text-zinc-500 mt-2 uppercase font-bold tracking-widest">Free Flash Core</p>
                    </div>
                  )}
                </div>
              </div>

              <button
                onClick={handlePost}
                disabled={!content.title || !!loading}
                className="w-full bg-white text-black font-black py-4 rounded-2xl hover:bg-zinc-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-white/5 active:scale-95"
              >
                <Sparkles className="w-5 h-5 text-red-600" /> PUBLISH PROJECT
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default StudioView;

import React, { useState } from 'react';
