import React, { useState, useEffect } from 'react';
import { ChannelProfile } from '../types';
import { generateChannelBranding } from '../services/geminiService';
import { Sparkles, Save, RefreshCw, Type as TypeIcon, AlignLeft, Palette } from 'lucide-react';

interface BrandingViewProps {
  profile: ChannelProfile | null;
  onUpdate: (profile: ChannelProfile) => void;
}

const BrandingView: React.FC<BrandingViewProps> = ({ profile, onUpdate }) => {
  const [niche, setNiche] = useState(profile?.niche || '');
  const [loading, setLoading] = useState(false);
  const [localProfile, setLocalProfile] = useState<ChannelProfile | null>(profile);

  useEffect(() => {
    if (profile && !localProfile) {
      setLocalProfile(profile);
    }
  }, [profile]);

  const handleGenerate = async () => {
    if (!niche) return;
    setLoading(true);
    try {
      const result = await generateChannelBranding(niche);
      setLocalProfile(result);
    } catch (error) {
      console.error(error);
      alert("Something went wrong while generating branding. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field: keyof ChannelProfile, value: string) => {
    if (localProfile) {
      setLocalProfile({ ...localProfile, [field]: value });
    }
  };

  const handleSave = () => {
    if (localProfile) {
      onUpdate({ ...localProfile, niche });
      alert("Channel Profile Saved!");
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="bg-zinc-900/50 p-8 rounded-3xl border border-zinc-800 backdrop-blur-sm">
        <h2 className="text-2xl font-bold mb-2 text-white">Channel Architect</h2>
        <p className="text-zinc-400 mb-6">Define your niche and let AI build your brand identity, then fine-tune it yourself.</p>

        <div className="flex flex-col md:flex-row gap-4 mb-10">
          <div className="flex-1 relative">
            <input
              type="text"
              value={niche}
              onChange={(e) => setNiche(e.target.value)}
              placeholder="e.g., Space Exploration, Cooking for Students, AI News"
              className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-4 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all placeholder:text-zinc-700"
            />
          </div>
