                >
                  {loading === 'thinking' ? <Loader2 className="w-4 h-4 animate-spin mx-auto" /> : 'Execute Deep Thought'}
                </button>
              </div>

              {thinkingResult && (
                <div className="bg-zinc-950/50 border border-zinc-800/50 p-3 rounded-xl max-h-40 overflow-y-auto text-[11px] text-zinc-400 italic">
                  {thinkingResult}
                </div>
              )}

              <div className="pt-4 border-t border-zinc-800">
                <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Video Understanding</label>
                <input type="file" ref={videoInputRef} onChange={handleVideoAnalysis} accept="video/*" className="hidden" />
